---@class StructGoalSchedule
local StructGoalSchedule = LxClass("StructGoalSchedule", nil)
function StructGoalSchedule:StructGoalSchedule()
    self.eventType = 0                  --条件号
    self.schedule = 0                   --当前进度
    self.goal = 0                       --目标进度
end
function StructGoalSchedule:CreateByPb(pb)
    self.eventType = pb.eventType
    self.multiple = pb.multiple

    local schedule = pb.schedule
    local goal = pb.goal
    if self.multiple == 1 then
        schedule = tonumber(schedule)/100
        goal = tonumber(goal)/100
    end

    self.schedule = schedule
    self.goal = goal

end
return StructGoalSchedule